import sys

class ListNode:
    __slots__ = ('val', 'next')
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def detectCycle(self, head: ListNode | None) -> ListNode | None:
        slow = fast = head
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow is fast:
                # find entry
                ptr1 = head
                ptr2 = slow
                while ptr1 is not ptr2:
                    ptr1 = ptr1.next
                    ptr2 = ptr2.next
                return ptr1
        return None

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    values = [int(next(it)) for _ in range(n)]
    # read next pointers, one per line (could be more than n lines until -1?)
    # According to format, there are n lines of next indices.
    next_idxs = []
    for _ in range(n):
        try:
            nxt = int(next(it))
        except StopIteration:
            nxt = -1
        next_idxs.append(nxt)
    nodes = [ListNode(v) for v in values]
    for i, nxt in enumerate(next_idxs):
        if nxt == -1:
            nodes[i].next = None
        else:
            # nxt is index (1‑based?) examples: first node next=1 points to node index 1 (second node)
            # Assuming 0‑based index given directly.
            if 0 <= nxt < n:
                nodes[i].next = nodes[nxt]
            else:
                nodes[i].next = None
    head = nodes[0] if n > 0 else None
    sol = Solution()
    entry = sol.detectCycle(head)
    print(entry.val if entry else -1)

