#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* detectCycle(ListNode* head) {
        ListNode *slow = head, *fast = head;
        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
            if (slow == fast) {
                ListNode *ptr1 = head, *ptr2 = slow;
                while (ptr1 != ptr2) {
                    ptr1 = ptr1->next;
                    ptr2 = ptr2->next;
                }
                return ptr1;
            }
        }
        return nullptr;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    vector<int> nxtIdx(n);
    for (int i = 0; i < n; ++i) {
        if (!(cin >> nxtIdx[i])) nxtIdx[i] = -1;
    }
    vector<ListNode*> nodes;
    nodes.reserve(n);
    for (int v : vals) nodes.push_back(new ListNode(v));
    for (int i = 0; i < n; ++i) {
        int idx = nxtIdx[i];
        if (idx == -1) nodes[i]->next = nullptr;
        else if (0 <= idx && idx < n) nodes[i]->next = nodes[idx];
        else nodes[i]->next = nullptr;
    }
    ListNode* head = n ? nodes[0] : nullptr;
    Solution sol;
    ListNode* entry = sol.detectCycle(head);
    if (entry) cout << entry->val << "\n";
    else cout << -1 << "\n";
    return 0;
}
